var COURSE_AR_PL = [{day: 1, title: `التحيات والعبارات الأولى`, title_native: `Powitania i pierwsze zwroty`, focus: `ستبدأ بكلمات Polskie بسيطة تستخدمها فور وصولك إلى وارسو أو كراكوف. الهدف هو أن تعرف كيف تلقي التحية وتودّع الناس بأدب.`, vocab: [{pl: `cześć`, ar: `مرحباً / وداعاً`, ipa: `تشيشْتش`},{pl: `dzień dobry`, ar: `صباح الخير / نهارك سعيد`, ipa: `جين دوبري`},{pl: `dobry wieczór`, ar: `مساء الخير`, ipa: `دوبري فييتشور`},{pl: `do widzenia`, ar: `إلى اللقاء`, ipa: `دو فيدزينيا`},{pl: `proszę`, ar: `من فضلك / تفضّل`, ipa: `بروشه`},{pl: `dziękuję`, ar: `شكراً`, ipa: `جينكوويه`},{pl: `tak`, ar: `نعم`, ipa: `تاك`},{pl: `nie`, ar: `لا`, ipa: `نيه`},{pl: `przepraszam`, ar: `عفواً / آسف`, ipa: `بشه براشام`}], phrases: [{pl: `Cześć!`, ar: `مرحباً!`, ipa: `تشيشْتش`},{pl: `Dzień dobry.`, ar: `صباح الخير.`, ipa: `جين دوبري`},{pl: `Dobry wieczór.`, ar: `مساء الخير.`, ipa: `دوبري فييتشور`},{pl: `Do widzenia.`, ar: `إلى اللقاء.`, ipa: `دو فيدزينيا`},{pl: `Dziękuję bardzo.`, ar: `شكراً جزيلاً.`, ipa: `جينكوويه باردزو`},{pl: `Przepraszam.`, ar: `عفواً / آسف.`, ipa: `بشه براشام`}], grammar: `في البولندية، التحية Dzień dobry رسمية ومناسبة في المتاجر والفنادق والمطاعم. كلمة Cześć غير رسمية وتستخدم مع الأصدقاء أو الأشخاص القريبين في العمر. كلمة proszę مهمة جداً لأنها تعني “من فضلك” وأيضاً “تفضل” عند إعطاء شيء لشخص.`, practice: [`قل التحية المناسبة عند دخول فندق في وارسو.`,`ترجم إلى البولندية: شكراً جزيلاً.`,`اختر بين Cześć وDzień dobry عند الحديث مع موظف في محطة قطار.`,`كرر كلمة przepraszam خمس مرات بصوت واضح.`,`اكتب حواراً قصيراً من سطرين: مرحباً ثم إلى اللقاء.`]},{day: 2, title: `التعارف وتقديم النفس`, title_native: `Przedstawianie się`, focus: `في هذا اليوم ستتعلم كيف تقول اسمك وتسأل عن اسم شخص آخر. ستستخدم هذه العبارات عند لقاء مضيف في كراكوف أو شخص في جولة سياحية.`, vocab: [{pl: `imię`, ar: `اسم أول`, ipa: `إيميه`},{pl: `nazwisko`, ar: `اسم العائلة`, ipa: `نازفيسكو`},{pl: `ja`, ar: `أنا`, ipa: `يا`},{pl: `ty`, ar: `أنت`, ipa: `تي`},{pl: `pan`, ar: `حضرتك / السيد`, ipa: `بان`},{pl: `pani`, ar: `حضرتك / السيدة`, ipa: `باني`},{pl: `miło`, ar: `بسرور / لطيف`, ipa: `ميوو`},{pl: `turysta`, ar: `سائح`, ipa: `توريستا`},{pl: `turystka`, ar: `سائحة`, ipa: `توريستكا`}], phrases: [{pl: `Mam na imię Ahmed.`, ar: `اسمي أحمد.`, ipa: `مام نا إيميه أحمد`},{pl: `Jak masz na imię?`, ar: `ما اسمك؟`, ipa: `ياك ماش نا إيميه`},{pl: `Miło mi.`, ar: `تشرفت بمعرفتك.`, ipa: `ميوو مي`},{pl: `Jestem turystą.`, ar: `أنا سائح.`, ipa: `ييستم توريستو`},{pl: `Jestem turystką.`, ar: `أنا سائحة.`, ipa: `ييستم توريستكو`},{pl: `A pan?`, ar: `وحضرتك؟`, ipa: `آ بان`}], grammar: `الفعل jestem يعني “أنا أكون” ويستخدم كثيراً للتعريف بالنفس: Jestem turystą. إذا كنت رجلاً تقول turystą، وإذا كنتِ امرأة تقولين turystką. في المواقف الرسمية استخدم pan للرجل وpani للمرأة بدلاً من ty.`, practice: [`قل بالبولندية: اسمي [اسمك].`,`اسأل شخصاً بطريقة غير رسمية: ما اسمك؟`,`قل إنك سائح أو سائحة.`,`استخدم Miło mi بعد سماع اسم شخص.`,`تخيل أنك في جولة في كراكوف واكتب ثلاث جمل للتعارف.`]},{day: 3, title: `الأرقام من 0 إلى 20`, title_native: `Liczby od 0 do 20`, focus: `الأرقام ضرورية عند شراء تذكرة ترام في وارسو أو طلب قهوة وسعرها. ستتعلم العد الأساسي وفهم الأسعار البسيطة.`, vocab: [{pl: `zero`, ar: `صفر`, ipa: `زيرو`},{pl: `jeden`, ar: `واحد`, ipa: `ييدن`},{pl: `dwa`, ar: `اثنان`, ipa: `دفا`},{pl: `trzy`, ar: `ثلاثة`, ipa: `تشي`},{pl: `cztery`, ar: `أربعة`, ipa: `تشتيري`},{pl: `pięć`, ar: `خمسة`, ipa: `پيينتش`},{pl: `sześć`, ar: `ستة`, ipa: `شيشْتش`},{pl: `siedem`, ar: `سبعة`, ipa: `شيدم`},{pl: `osiem`, ar: `ثمانية`, ipa: `أوشم`},{pl: `dziesięć`, ar: `عشرة`, ipa: `جِشينتش`}], phrases: [{pl: `Jeden bilet, proszę.`, ar: `تذكرة واحدة، من فضلك.`, ipa: `ييدن بيليت بروشه`},{pl: `Dwie kawy, proszę.`, ar: `قهوتان، من فضلك.`, ipa: `دفييه كافي بروشه`},{pl: `Ile to kosztuje?`, ar: `كم يكلف هذا؟`, ipa: `إيله تو كوشتوييه`},{pl: `To kosztuje dziesięć złotych.`, ar: `هذا يكلف عشرة زلوتي.`, ipa: `تو كوشتوييه جِشينتش زووتِخ`},{pl: `Mam pięć złotych.`, ar: `لدي خمسة زلوتي.`, ipa: `مام پيينتش زووتِخ`},{pl: `Numer trzy.`, ar: `رقم ثلاثة.`, ipa: `نومر تشي`}], grammar: `كلمة dwa تتغير أحياناً حسب الاسم، فمع kawa تصبح dwie kawy. لا تقلق من كل التفاصيل الآن؛ احفظ العبارات الجاهزة مثل jeden bilet وdwie kawy لأنها مفيدة في السفر.`, practice: [`عد من zero إلى dziesięć بصوت عالٍ.`,`قل: تذكرة واحدة من فضلك.`,`اسأل عن السعر بالبولندية.`,`تخيل أن القهوة تكلف خمسة زلوتي وقل الجملة.`,`اكتب ثلاثة أرقام بولندية مع معناها العربي.`]},{day: 4, title: `العبارات الأساسية للنجاة`, title_native: `Podstawowe zwroty przetrwania`, focus: `ستتعلم عبارات تساعدك عندما لا تفهم أو تحتاج إلى المساعدة في مدينة مثل غدانسك. هذه الجمل تمنحك الثقة في المواقف المفاجئة.`, vocab: [{pl: `pomoc`, ar: `مساعدة`, ipa: `بوموتس`},{pl: `rozumiem`, ar: `أفهم`, ipa: `روزوميم`},{pl: `mówię`, ar: `أتكلم`, ipa: `موڤيه`},{pl: `polski`, ar: `البولندية`, ipa: `پولسكي`},{pl: `angielski`, ar: `الإنجليزية`, ipa: `أنجييلسكي`},{pl: `arabski`, ar: `العربية`, ipa: `أرابسكي`},{pl: `wolno`, ar: `ببطء`, ipa: `ڤولنو`},{pl: `jeszcze raz`, ar: `مرة أخرى`, ipa: `ييشچه راز`},{pl: `problem`, ar: `مشكلة`, ipa: `پروبليم`}], phrases: [{pl: `Nie rozumiem.`, ar: `لا أفهم.`, ipa: `نيه روزوميم`},{pl: `Czy mówi pan po angielsku?`, ar: `هل تتكلم الإنجليزية؟`, ipa: `تشي موڤي بان پو أنجييلسكو`},{pl: `Czy mówi pani po angielsku?`, ar: `هل تتكلمين الإنجليزية؟`, ipa: `تشي موڤي باني پو أنجييلسكو`},{pl: `Proszę mówić wolno.`, ar: `من فضلك تحدث ببطء.`, ipa: `بروشه موڤيتش ڤولنو`},{pl: `Jeszcze raz, proszę.`, ar: `مرة أخرى، من فضلك.`, ipa: `ييشچه راز بروشه`},{pl: `Potrzebuję pomocy.`, ar: `أحتاج إلى مساعدة.`, ipa: `پوتشيبوييه پوموتسي`}], grammar: `السؤال في البولندية يمكن أن يبدأ بكلمة Czy، وهي تشبه أداة سؤال عامة. الجملة Czy mówi pan po angielsku? رسمية ومناسبة مع موظف أو شخص لا تعرفه. عبارة po angielsku تعني “بالإنجليزية”، وpo polsku تعني “بالبولندية”.`, practice: [`قل: لا أفهم.`,`اطلب من شخص أن يتحدث ببطء.`,`اسأل رجلاً بطريقة مهذبة إن كان يتحدث الإنجليزية.`,`غيّر angielsku إلى polsku في الجملة.`,`اكتب موقفاً تحتاج فيه إلى قول Potrzebuję pomocy.`]},{day: 5, title: `في المطار والوصول`, title_native: `Na lotnisku i po przylocie`, focus: `في مطار شوبان في وارسو ستحتاج إلى فهم كلمات مثل جواز السفر والأمتعة والخروج. هذا الدرس يركز على أول ساعة بعد الهبوط.`, vocab: [{pl: `lotnisko`, ar: `مطار`, ipa: `لوتنيسكو`},{pl: `paszport`, ar: `جواز سفر`, ipa: `پاشپورت`},{pl: `bagaż`, ar: `أمتعة`, ipa: `باغاش`},{pl: `walizka`, ar: `حقيبة سفر`, ipa: `ڤاليزكا`},{pl: `wyjście`, ar: `خروج`, ipa: `ڤييشْتشيه`},{pl: `przylot`, ar: `وصول الطائرة`, ipa: `پشيلوت`},{pl: `kontrola`, ar: `تفتيش / مراقبة`, ipa: `كونترولَا`},{pl: `taksówka`, ar: `سيارة أجرة`, ipa: `تاكسوفكا`},{pl: `autobus`, ar: `حافلة`, ipa: `أوتوبوس`}], phrases: [{pl: `Gdzie jest wyjście?`, ar: `أين المخرج؟`, ipa: `گجيه ييست ڤييشْتشيه`},{pl: `To jest mój paszport.`, ar: `هذا جواز سفري.`, ipa: `تو ييست موي پاشپورت`},{pl: `Gdzie jest bagaż?`, ar: `أين الأمتعة؟`, ipa: `گجيه ييست باغاش`},{pl: `Potrzebuję taksówki.`, ar: `أحتاج إلى سيارة أجرة.`, ipa: `پوتشيبوييه تاكسوفكي`},{pl: `Jadę do centrum.`, ar: `أنا ذاهب إلى المركز.`, ipa: `يادِه دو تسنتروم`},{pl: `Jeden bilet na autobus, proszę.`, ar: `تذكرة واحدة للحافلة، من فضلك.`, ipa: `ييدن بيليت نا أوتوبوس بروشه`}], grammar: `كلمة gdzie تعني “أين”، وتستخدم مباشرة مع jest: Gdzie jest...? أي “أين يوجد...؟”. احفظ هذه البنية لأنها ستظهر في كل مكان: Gdzie jest hotel? Gdzie jest toaleta? Gdzie jest autobus?`, practice: [`اسأل: أين المخرج؟`,`قل: هذا جواز سفري.`,`اطلب سيارة أجرة.`,`قل إنك ذاهب إلى centrum.`,`تخيل أنك في مطار وارسو واكتب ثلاث جمل مفيدة.`]},{day: 6, title: `الاتجاهات في المدينة`, title_native: `Kierunki w mieście`, focus: `في شوارع كراكوف القديمة أو وسط وارسو، ستحتاج إلى فهم اليمين واليسار والقريب والبعيد. ستتعلم كيف تسأل وتفهم الاتجاهات الأساسية.`, vocab: [{pl: `prawo`, ar: `يمين`, ipa: `پراڤو`},{pl: `lewo`, ar: `يسار`, ipa: `ليفو`},{pl: `prosto`, ar: `إلى الأمام`, ipa: `پروستو`},{pl: `tutaj`, ar: `هنا`, ipa: `توتاي`},{pl: `tam`, ar: `هناك`, ipa: `تام`},{pl: `blisko`, ar: `قريب`, ipa: `بليسكو`},{pl: `daleko`, ar: `بعيد`, ipa: `داليكو`},{pl: `ulica`, ar: `شارع`, ipa: `أوليتسا`},{pl: `plac`, ar: `ساحة`, ipa: `پلاتس`},{pl: `most`, ar: `جسر`, ipa: `موست`}], phrases: [{pl: `Gdzie jest ulica Długa?`, ar: `أين شارع دووغا؟`, ipa: `گجيه ييست أوليتسا دووگا`},{pl: `Proszę iść prosto.`, ar: `اذهب إلى الأمام، من فضلك.`, ipa: `بروشه إيشتش پروستو`},{pl: `W prawo.`, ar: `إلى اليمين.`, ipa: `ڤ پراڤو`},{pl: `W lewo.`, ar: `إلى اليسار.`, ipa: `ڤ ليفو`},{pl: `Czy to daleko?`, ar: `هل هذا بعيد؟`, ipa: `تشي تو داليكو`},{pl: `To jest blisko.`, ar: `هذا قريب.`, ipa: `تو ييست بليسكو`}], grammar: `الفعل iść يعني “يمشي / يذهب سيراً”. في التعليمات الرسمية تسمع Proszę iść، أي “من فضلك اذهب/امشِ”. الاتجاهات غالباً تأتي قصيرة: prosto، w prawo، w lewo.`, practice: [`قل: إلى اليمين، ثم إلى اليسار.`,`اسأل إن كان المكان بعيداً.`,`اشرح لشخص: امشِ إلى الأمام.`,`اسأل عن شارع باسم تختاره.`,`ارسم طريقاً بسيطاً واكتب ثلاث تعليمات بالبولندية.`]},{day: 7, title: `الفندق وتسجيل الدخول`, title_native: `Hotel i zameldowanie`, focus: `عند الوصول إلى فندق في فروتسواف أو بوزنان، تحتاج إلى كلمات الغرفة والحجز والمفتاح. هذا الدرس يساعدك على تسجيل الدخول بسهولة.`, vocab: [{pl: `hotel`, ar: `فندق`, ipa: `هوتيل`},{pl: `pokój`, ar: `غرفة`, ipa: `پوكوي`},{pl: `rezerwacja`, ar: `حجز`, ipa: `ريزيرڤاتسيا`},{pl: `klucz`, ar: `مفتاح`, ipa: `كلوتش`},{pl: `paszport`, ar: `جواز سفر`, ipa: `پاشپورت`},{pl: `noc`, ar: `ليلة`, ipa: `نوتس`},{pl: `łóżko`, ar: `سرير`, ipa: `ووشكو`},{pl: `winda`, ar: `مصعد`, ipa: `ڤيندا`},{pl: `recepcja`, ar: `الاستقبال`, ipa: `ريتسيپتسيا`}], phrases: [{pl: `Mam rezerwację.`, ar: `لدي حجز.`, ipa: `مام ريزيرڤاتسيه`},{pl: `Na nazwisko Cannon.`, ar: `باسم كانون.`, ipa: `نا نازفيسكو كانون`},{pl: `Poproszę klucz.`, ar: `أريد المفتاح، من فضلك.`, ipa: `پوپروشه كلوتش`},{pl: `Gdzie jest winda?`, ar: `أين المصعد؟`, ipa: `گجيه ييست ڤيندا`},{pl: `Pokój na jedną noc.`, ar: `غرفة لليلة واحدة.`, ipa: `پوكوي نا ييدنو نوتس`},{pl: `Czy jest śniadanie?`, ar: `هل يوجد فطور؟`, ipa: `تشي ييست شنيادانيه`}], grammar: `عبارة Mam rezerwację تعني حرفياً “لدي حجز”، وهي أكثر جملة تحتاجها في الفندق. كلمة na تستخدم في عبارة Na nazwisko... بمعنى “باسم...”. عند طلب شيء بأدب، يمكنك استخدام Poproszę ثم اسم الشيء.`, practice: [`قل: لدي حجز.`,`اسأل عن المصعد.`,`اطلب المفتاح بأدب.`,`قل: غرفة لليلة واحدة.`,`تخيل أنك في فندق في فروتسواف واكتب حواراً من أربع جمل.`]},{day: 8, title: `الوقت والأيام`, title_native: `Czas i dni tygodnia`, focus: `ستحتاج إلى الوقت عند حجز قطار أو معرفة موعد الإفطار في الفندق. اليوم يعرّفك على الساعة وأيام الأسبوع بطريقة عملية.`, vocab: [{pl: `czas`, ar: `وقت`, ipa: `تشاس`},{pl: `godzina`, ar: `ساعة`, ipa: `گودجينا`},{pl: `dzisiaj`, ar: `اليوم`, ipa: `جيشاي`},{pl: `jutro`, ar: `غداً`, ipa: `يوترو`},{pl: `wczoraj`, ar: `أمس`, ipa: `فتشوراي`},{pl: `poniedziałek`, ar: `الاثنين`, ipa: `پونييجاوِك`},{pl: `wtorek`, ar: `الثلاثاء`, ipa: `فتورِك`},{pl: `środa`, ar: `الأربعاء`, ipa: `شرودا`},{pl: `czwartek`, ar: `الخميس`, ipa: `چفارتِك`},{pl: `piątek`, ar: `الجمعة`, ipa: `پيونتِك`}], phrases: [{pl: `Która godzina?`, ar: `كم الساعة؟`, ipa: `كتورا گودجينا`},{pl: `Jest ósma.`, ar: `الساعة الثامنة.`, ipa: `ييست أوسما`},{pl: `Dzisiaj jadę do Krakowa.`, ar: `اليوم أذهب إلى كراكوف.`, ipa: `جيشاي يادِه دو كراكوفا`},{pl: `Jutro mam rezerwację.`, ar: `غداً لدي حجز.`, ipa: `يوترو مام ريزيرڤاتسيه`},{pl: `O której jest śniadanie?`, ar: `في أي ساعة الفطور؟`, ipa: `أو كتوري ييست شنيادانيه`},{pl: `W piątek.`, ar: `يوم الجمعة.`, ipa: `ڤ پيونتِك`}], grammar: `في السؤال عن الساعة تستخدم Która godzina? ومع المواعيد تستخدم O której...? أي “في أي ساعة؟”. الأيام في البولندية قد تتغير قليلاً بعد حرف w، لكن احفظ العبارات كما هي: w piątek، w czwartek.`, practice: [`اسأل: كم الساعة؟`,`قل: اليوم أذهب إلى كراكوف.`,`اسأل عن وقت الفطور.`,`اكتب ثلاثة أيام بالأحرف البولندية.`,`استخدم jutro في جملة عن حجز أو رحلة.`]},{day: 9, title: `طلب القهوة والوجبات الخفيفة`, title_native: `Zamawianie kawy i przekąsek`, focus: `في مقهى في كراكوف أو غدانسك ستحتاج إلى طلب قهوة أو شاي أو قطعة كعك. ستتدرب على الجمل المهذبة والطلبات البسيطة.`, vocab: [{pl: `kawa`, ar: `قهوة`, ipa: `كاڤا`},{pl: `herbata`, ar: `شاي`, ipa: `هيرباتا`},{pl: `woda`, ar: `ماء`, ipa: `ڤودا`},{pl: `mleko`, ar: `حليب`, ipa: `مليكو`},{pl: `cukier`, ar: `سكر`, ipa: `تسوكيير`},{pl: `ciasto`, ar: `كعك`, ipa: `تشاستو`},{pl: `kanapka`, ar: `شطيرة`, ipa: `كاناپكا`},{pl: `rachunek`, ar: `الفاتورة`, ipa: `راخونِك`},{pl: `stolik`, ar: `طاولة`, ipa: `ستوليك`}], phrases: [{pl: `Poproszę kawę.`, ar: `أريد قهوة، من فضلك.`, ipa: `پوپروشه كاڤه`},{pl: `Poproszę herbatę.`, ar: `أريد شاياً، من فضلك.`, ipa: `پوپروشه هيرباته`},{pl: `Bez cukru, proszę.`, ar: `بدون سكر، من فضلك.`, ipa: `بيز تسوكرو بروشه`},{pl: `Z mlekiem, proszę.`, ar: `مع الحليب، من فضلك.`, ipa: `ز مليكيم بروشه`},{pl: `Czy jest wolny stolik?`, ar: `هل توجد طاولة فارغة؟`, ipa: `تشي ييست ڤولني ستوليك`},{pl: `Rachunek, proszę.`, ar: `الفاتورة، من فضلك.`, ipa: `راخونِك بروشه`}], grammar: `عند الطلب، كلمة Poproszę مفيدة جداً وتعني “أريد من فضلك”. ستلاحظ أن kawa تصبح kawę بعد Poproszę، وهذا بسبب حالة نحوية، لكن في السفر يكفي حفظ الصيغة الجاهزة: Poproszę kawę.`, practice: [`اطلب قهوة مع الحليب.`,`اطلب شاياً بدون سكر.`,`اسأل عن طاولة فارغة.`,`اطلب الفاتورة.`,`اكتب طلباً من ثلاث كلمات في مقهى بولندي.`]},{day: 10, title: `الطعام في المطعم`, title_native: `Jedzenie w restauracji`, focus: `في مطعم بولندي تقليدي قد تطلب pierogi أو حساء. ستتعلم أسماء أطعمة وأسئلة بسيطة عن القائمة.`, vocab: [{pl: `restauracja`, ar: `مطعم`, ipa: `ريستورانتسيا`},{pl: `menu`, ar: `قائمة الطعام`, ipa: `مينو`},{pl: `zupa`, ar: `حساء`, ipa: `زوپا`},{pl: `pierogi`, ar: `بيروغي / فطائر بولندية`, ipa: `پييِروگي`},{pl: `mięso`, ar: `لحم`, ipa: `ميينسو`},{pl: `ryba`, ar: `سمك`, ipa: `ريبا`},{pl: `kurczak`, ar: `دجاج`, ipa: `كورتشاك`},{pl: `sałatka`, ar: `سلطة`, ipa: `ساواتكا`},{pl: `deser`, ar: `حلوى`, ipa: `ديزير`},{pl: `smaczne`, ar: `لذيذ`, ipa: `سماچنه`}], phrases: [{pl: `Czy mogę prosić menu?`, ar: `هل يمكنني طلب القائمة؟`, ipa: `تشي موگه پروشيتش مينو`},{pl: `Poproszę pierogi.`, ar: `أريد بيروغي، من فضلك.`, ipa: `پوپروشه پييِروگي`},{pl: `Co pan poleca?`, ar: `ماذا تنصح؟`, ipa: `تسو بان پوليتسا`},{pl: `Co pani poleca?`, ar: `ماذا تنصحين؟`, ipa: `تسو باني پوليتسا`},{pl: `To jest bardzo smaczne.`, ar: `هذا لذيذ جداً.`, ipa: `تو ييست باردزو سماچنه`},{pl: `Nie jem mięsa.`, ar: `لا آكل اللحم.`, ipa: `نيه ييم ميينسا`}], grammar: `السؤال Czy mogę...? يعني “هل أستطيع...؟” وهو مهذب جداً. كلمة poleca تعني “ينصح/توصي”، وتستخدم مع pan أو pani في المطاعم. إذا كان لديك تفضيل غذائي، احفظ Nie jem... ثم اسم الطعام.`, practice: [`اطلب القائمة بأدب.`,`قل: لا آكل اللحم.`,`اطلب pierogi.`,`اسأل النادل عما ينصح به.`,`اكتب جملة تمدح الطعام.`]},{day: 11, title: `التسوق والأسعار`, title_native: `Zakupy i ceny`, focus: `في سوق محلي في وارسو أو متجر هدايا في زاكوباني، ستسأل عن السعر والمقاس والدفع. هذا الدرس عملي جداً للشراء اليومي.`, vocab: [{pl: `sklep`, ar: `متجر`, ipa: `سكليپ`},{pl: `cena`, ar: `سعر`, ipa: `تسينا`},{pl: `ile`, ar: `كم`, ipa: `إيله`},{pl: `drogo`, ar: `غالي`, ipa: `دروگو`},{pl: `tanio`, ar: `رخيص`, ipa: `تانيو`},{pl: `karta`, ar: `بطاقة`, ipa: `كارتا`},{pl: `gotówka`, ar: `نقد`, ipa: `گوتوفكا`},{pl: `paragon`, ar: `إيصال`, ipa: `پاراگون`},{pl: `torba`, ar: `كيس / حقيبة`, ipa: `توربا`},{pl: `pamiątka`, ar: `تذكار`, ipa: `پاميونتكا`}], phrases: [{pl: `Ile to kosztuje?`, ar: `كم يكلف هذا؟`, ipa: `إيله تو كوشتوييه`},{pl: `To za drogo.`, ar: `هذا غالٍ جداً.`, ipa: `تو زا دروگو`},{pl: `Czy mogę płacić kartą?`, ar: `هل يمكنني الدفع بالبطاقة؟`, ipa: `تشي موگه پواچيتش كارتو`},{pl: `Poproszę torbę.`, ar: `أريد كيساً، من فضلك.`, ipa: `پوپروشه توربه`},{pl: `Czy ma pan paragon?`, ar: `هل لديك إيصال؟`, ipa: `تشي ما بان پاراگون`},{pl: `Szukam pamiątki.`, ar: `أبحث عن تذكار.`, ipa: `شوكام پاميونتكي`}], grammar: `الفعل szukam يعني “أبحث عن”، وبعده يتغير الاسم غالباً. لا تحتاج إلى معرفة القاعدة كاملة الآن؛ احفظ عبارات مثل Szukam hotelu وSzukam pamiątki لأنها شائعة للمسافرين.`, practice: [`اسأل عن السعر.`,`قل إن الشيء غالي جداً.`,`اسأل إن كان يمكنك الدفع بالبطاقة.`,`اطلب كيساً.`,`تخيل أنك في متجر هدايا واكتب ثلاث جمل.`]},{day: 12, title: `وسائل النقل داخل المدينة`, title_native: `Transport w mieście`, focus: `في المدن البولندية ستستخدم الترام والحافلة والمترو. ستتعلم كيف تسأل عن التذاكر والمحطات والاتجاهات.`, vocab: [{pl: `tramwaj`, ar: `ترام`, ipa: `ترامڤاي`},{pl: `autobus`, ar: `حافلة`, ipa: `أوتوبوس`},{pl: `metro`, ar: `مترو`, ipa: `ميترو`},{pl: `bilet`, ar: `تذكرة`, ipa: `بيليت`},{pl: `przystanek`, ar: `محطة توقف`, ipa: `پشيستانِك`},{pl: `stacja`, ar: `محطة`, ipa: `ستاتسيا`},{pl: `centrum`, ar: `المركز`, ipa: `تسنتروم`},{pl: `linia`, ar: `خط`, ipa: `لينيا`},{pl: `rozkład`, ar: `جدول المواعيد`, ipa: `روزكواد`},{pl: `kontroler`, ar: `مفتش التذاكر`, ipa: `كونترولير`}], phrases: [{pl: `Gdzie jest przystanek?`, ar: `أين محطة التوقف؟`, ipa: `گجيه ييست پشيستانِك`},{pl: `Jaki bilet do centrum?`, ar: `أي تذكرة إلى المركز؟`, ipa: `ياكي بيليت دو تسنتروم`},{pl: `Czy ten tramwaj jedzie do centrum?`, ar: `هل هذا الترام يذهب إلى المركز؟`, ipa: `تشي تين ترامڤاي ييدجيه دو تسنتروم`},{pl: `Poproszę bilet jednodniowy.`, ar: `أريد تذكرة ليوم واحد.`, ipa: `پوپروشه بيليت ييدنودنيوڤي`},{pl: `Muszę skasować bilet.`, ar: `يجب أن أفعّل التذكرة.`, ipa: `موشه سكاسوڤاتش بيليت`},{pl: `To moja stacja.`, ar: `هذه محطتي.`, ipa: `تو مويا ستاتسيا`}], grammar: `الفعل jedzie يعني “يذهب/يسير” للمركبات. استخدم Czy ten tramwaj jedzie do...? لتسأل إن كان الترام يذهب إلى مكان معين. في بولندا غالباً تحتاج إلى تفعيل التذكرة بعد الصعود، لذلك عبارة skasować bilet مهمة.`, practice: [`اسأل عن محطة الترام.`,`اسأل إن كان الحافلة تذهب إلى المركز.`,`اطلب تذكرة ليوم واحد.`,`قل: هذه محطتي.`,`اكتب جملة عن تفعيل التذكرة.`]},{day: 13, title: `السفر بالقطار بين المدن`, title_native: `Podróż pociągiem`, focus: `القطارات وسيلة ممتازة بين وارسو وكراكوف وغدانسك. ستتعلم كلمات الرصيف، القطار، المقعد، وشراء التذكرة.`, vocab: [{pl: `pociąg`, ar: `قطار`, ipa: `پوتشونگ`},{pl: `dworzec`, ar: `محطة قطار`, ipa: `دڤوژيتس`},{pl: `peron`, ar: `رصيف`, ipa: `پيرون`},{pl: `miejsce`, ar: `مقعد / مكان`, ipa: `مييسْتسه`},{pl: `wagon`, ar: `عربة قطار`, ipa: `ڤاگون`},{pl: `opóźnienie`, ar: `تأخير`, ipa: `أوپوجنيينيه`},{pl: `bilet`, ar: `تذكرة`, ipa: `بيليت`},{pl: `powrotny`, ar: `ذهاب وعودة`, ipa: `پوڤروتني`},{pl: `jednorazowy`, ar: `لمرة واحدة`, ipa: `ييدنورازوڤي`},{pl: `kasa`, ar: `شباك التذاكر`, ipa: `كاسا`}], phrases: [{pl: `Poproszę bilet do Krakowa.`, ar: `أريد تذكرة إلى كراكوف.`, ipa: `پوپروشه بيليت دو كراكوفا`},{pl: `W jedną stronę.`, ar: `ذهاب فقط.`, ipa: `ڤ ييدنو سترونه`},{pl: `Tam i z powrotem.`, ar: `ذهاب وعودة.`, ipa: `تام إي ز پوڤروتيم`},{pl: `Z którego peronu?`, ar: `من أي رصيف؟`, ipa: `ز كتوريگو پيرونو`},{pl: `Czy pociąg jest opóźniony?`, ar: `هل القطار متأخر؟`, ipa: `تشي پوتشونگ ييست أوپوجنيوني`},{pl: `To moje miejsce.`, ar: `هذا مقعدي.`, ipa: `تو مويه مييسْتسه`}], grammar: `بعد do يأتي اسم المدينة غالباً بشكل مختلف: Kraków يصبح do Krakowa، Warszawa تصبح do Warszawy. احفظ أسماء المدن في عبارات جاهزة: bilet do Krakowa، bilet do Warszawy، bilet do Gdańska.`, practice: [`اطلب تذكرة إلى كراكوف.`,`قل: ذهاب فقط.`,`اسأل عن الرصيف.`,`اسأل إن كان القطار متأخراً.`,`اكتب جملة تقول فيها: هذا مقعدي.`]},{day: 14, title: `سيارة الأجرة وتطبيقات النقل`, title_native: `Taksówka i aplikacje transportowe`, focus: `في نهاية يوم طويل في وارسو قد تحتاج إلى تاكسي أو سيارة عبر تطبيق. ستتعلم كيف تقول العنوان وتسأل عن السعر ومدة الرحلة.`, vocab: [{pl: `taksówka`, ar: `سيارة أجرة`, ipa: `تاكسوفكا`},{pl: `adres`, ar: `عنوان`, ipa: `أدريس`},{pl: `kierowca`, ar: `سائق`, ipa: `كييروڤتسا`},{pl: `kurs`, ar: `رحلة / مشوار`, ipa: `كورس`},{pl: `cena`, ar: `سعر`, ipa: `تسينا`},{pl: `minuta`, ar: `دقيقة`, ipa: `مينوتا`},{pl: `szybko`, ar: `بسرعة`, ipa: `شيبكو`},{pl: `wolno`, ar: `ببطء`, ipa: `ڤولنو`},{pl: `aplikacja`, ar: `تطبيق`, ipa: `أپليكاتسيا`},{pl: `hotel`, ar: `فندق`, ipa: `هوتيل`}], phrases: [{pl: `Proszę jechać pod ten adres.`, ar: `من فضلك اذهب إلى هذا العنوان.`, ipa: `بروشه ييخاتش پود تين أدريس`},{pl: `Ile to będzie kosztować?`, ar: `كم سيكلف ذلك؟`, ipa: `إيله تو بِنجيه كوشتوڤاتش`},{pl: `Ile minut?`, ar: `كم دقيقة؟`, ipa: `إيله مينوت`},{pl: `Do hotelu, proszę.`, ar: `إلى الفندق، من فضلك.`, ipa: `دو هوتيلو بروشه`},{pl: `Proszę zatrzymać się tutaj.`, ar: `توقف هنا، من فضلك.`, ipa: `بروشه زاتشيماتش شيه توتاي`},{pl: `Czy mogę zapłacić kartą?`, ar: `هل يمكنني الدفع بالبطاقة؟`, ipa: `تشي موگه زاپواچيتش كارتو`}], grammar: `الفعل jechać يعني “يذهب/يسافر بمركبة”، عكس iść الذي يعني المشي. في التاكسي قل Proszę jechać... وليس Proszę iść. عند الوصول، عبارة Proszę zatrzymać się tutaj تعني “توقف هنا”.`, practice: [`قل للسائق: إلى الفندق من فضلك.`,`اسأل عن السعر.`,`اسأل عن عدد الدقائق.`,`اطلب التوقف هنا.`,`اكتب جملة تستخدم فيها adres.`]},{day: 15, title: `في المتحف والمعالم السياحية`, title_native: `W muzeum i przy atrakcjach`, focus: `عند زيارة متحف في وارسو أو قلعة فافل في كراكوف، ستحتاج إلى التذاكر، أوقات الافتتاح، والتصوير. هذا الدرس يناسب السياحة الثقافية.`, vocab: [{pl: `muzeum`, ar: `متحف`, ipa: `موزيوم`},{pl: `zamek`, ar: `قلعة`, ipa: `زامِك`},{pl: `bilet`, ar: `تذكرة`, ipa: `بيليت`},{pl: `wejście`, ar: `دخول / مدخل`, ipa: `ڤييشْتشيه`},{pl: `wyjście`, ar: `خروج`, ipa: `ڤييشْتشيه`},{pl: `otwarte`, ar: `مفتوح`, ipa: `أوتفارته`},{pl: `zamknięte`, ar: `مغلق`, ipa: `زامكْنيينته`},{pl: `zdjęcie`, ar: `صورة`, ipa: `زدينتشيه`},{pl: `przewodnik`, ar: `مرشد`, ipa: `پشيڤودنيك`},{pl: `wystawa`, ar: `معرض`, ipa: `ڤيستاڤا`}], phrases: [{pl: `Czy muzeum jest otwarte?`, ar: `هل المتحف مفتوح؟`, ipa: `تشي موزيوم ييست أوتفارته`},{pl: `O której zamykacie?`, ar: `في أي ساعة تغلقون؟`, ipa: `أو كتوري زاميكاتشيه`},{pl: `Poproszę dwa bilety.`, ar: `أريد تذكرتين.`, ipa: `پوپروشه دڤا بيليتي`},{pl: `Czy można robić zdjęcia?`, ar: `هل يمكن التقاط الصور؟`, ipa: `تشي موژنا روبتش زدينتشيا`},{pl: `Gdzie jest wejście?`, ar: `أين المدخل؟`, ipa: `گجيه ييست ڤييشْتشيه`},{pl: `Czy jest przewodnik po angielsku?`, ar: `هل يوجد مرشد بالإنجليزية؟`, ipa: `تشي ييست پشيڤودنيك پو أنجييلسكو`}], grammar: `كلمة można تعني “يمكن” وتستخدم لطلب الإذن بطريقة غير شخصية ومهذبة: Czy można...? عبارة robić zdjęcia تعني “التقاط الصور”. في الأماكن السياحية هذه من أهم العبارات.`, practice: [`اسأل إن كان المتحف مفتوحاً.`,`اطلب تذكرتين.`,`اسأل إن كان التصوير مسموحاً.`,`اسأل عن المدخل.`,`اكتب سؤالاً عن مرشد بالإنجليزية.`]},{day: 16, title: `الطقس والملابس`, title_native: `Pogoda i ubrania`, focus: `الطقس في بولندا قد يتغير بسرعة، خصوصاً في الربيع والخريف. ستتعلم كيف تتحدث عن البرد والمطر والملابس المناسبة.`, vocab: [{pl: `pogoda`, ar: `الطقس`, ipa: `پوگودا`},{pl: `zimno`, ar: `بارد`, ipa: `ژيمنو`},{pl: `ciepło`, ar: `دافئ`, ipa: `چيپوو`},{pl: `gorąco`, ar: `حار`, ipa: `گورونتسو`},{pl: `deszcz`, ar: `مطر`, ipa: `ديشتش`},{pl: `śnieg`, ar: `ثلج`, ipa: `شنييگ`},{pl: `wiatr`, ar: `ريح`, ipa: `ڤياتر`},{pl: `kurtka`, ar: `سترة`, ipa: `كورتكا`},{pl: `parasol`, ar: `مظلة`, ipa: `پاراسول`},{pl: `buty`, ar: `أحذية`, ipa: `بوتي`}], phrases: [{pl: `Jaka jest pogoda?`, ar: `كيف الطقس؟`, ipa: `ياكا ييست پوگودا`},{pl: `Jest zimno.`, ar: `الجو بارد.`, ipa: `ييست ژيمنو`},{pl: `Pada deszcz.`, ar: `المطر يهطل.`, ipa: `پادا ديشتش`},{pl: `Potrzebuję parasola.`, ar: `أحتاج إلى مظلة.`, ipa: `پوتشيبوييه پاراسولا`},{pl: `Mam kurtkę.`, ar: `لدي سترة.`, ipa: `مام كورتكه`},{pl: `Czy będzie śnieg?`, ar: `هل سيكون هناك ثلج؟`, ipa: `تشي بِنجيه شنييگ`}], grammar: `في البولندية غالباً تقول Jest zimno بدون فاعل واضح، مثل “الجو بارد”. عبارة Pada deszcz تعني حرفياً “المطر يسقط”. هذه العبارات ثابتة ومفيدة عند الحديث مع سكان محليين.`, practice: [`قل: الجو بارد.`,`قل: المطر يهطل.`,`اسأل عن الطقس.`,`قل إنك تحتاج إلى مظلة.`,`اكتب جملة عن سترة أو أحذية.`]},{day: 17, title: `الصحة والصيدلية`, title_native: `Zdrowie i apteka`, focus: `إذا احتجت دواءً بسيطاً أو نصيحة في صيدلية في بولندا، فهذه الكلمات مهمة. ستتعلم كيف تصف ألماً أو برداً بطريقة بسيطة.`, vocab: [{pl: `apteka`, ar: `صيدلية`, ipa: `أپتيكا`},{pl: `lekarz`, ar: `طبيب`, ipa: `ليكاش`},{pl: `lek`, ar: `دواء`, ipa: `ليك`},{pl: `ból`, ar: `ألم`, ipa: `بول`},{pl: `głowa`, ar: `رأس`, ipa: `گووڤا`},{pl: `brzuch`, ar: `بطن`, ipa: `بژوخ`},{pl: `gardło`, ar: `حلق`, ipa: `گاردوو`},{pl: `gorączka`, ar: `حمى`, ipa: `گورونچكا`},{pl: `alergia`, ar: `حساسية`, ipa: `أليرگيا`},{pl: `recepta`, ar: `وصفة طبية`, ipa: `ريتسيپتا`}], phrases: [{pl: `Gdzie jest apteka?`, ar: `أين الصيدلية؟`, ipa: `گجيه ييست أپتيكا`},{pl: `Boli mnie głowa.`, ar: `رأسي يؤلمني.`, ipa: `بولي منيه گووڤا`},{pl: `Boli mnie brzuch.`, ar: `بطني يؤلمني.`, ipa: `بولي منيه بژوخ`},{pl: `Mam gorączkę.`, ar: `لدي حمى.`, ipa: `مام گورونچكه`},{pl: `Potrzebuję lekarza.`, ar: `أحتاج إلى طبيب.`, ipa: `پوتشيبوييه ليكاشا`},{pl: `Czy potrzebna jest recepta?`, ar: `هل الوصفة الطبية ضرورية؟`, ipa: `تشي پوتشيبنا ييست ريتسيپتا`}], grammar: `للتعبير عن الألم تقول Boli mnie... ثم العضو المؤلم. لا تترجم حرفياً من العربية؛ الجملة البولندية تعني تقريباً “يؤلمني الرأس”. احفظ Boli mnie głowa وBoli mnie brzuch كعبارات جاهزة.`, practice: [`اسأل عن الصيدلية.`,`قل: رأسي يؤلمني.`,`قل: لدي حمى.`,`اسأل إن كانت الوصفة ضرورية.`,`تخيل أنك في صيدلية واكتب طلباً قصيراً.`]},{day: 18, title: `حالات الطوارئ والسلامة`, title_native: `Nagłe sytuacje i bezpieczeństwo`, focus: `لا أحد يريد الطوارئ، لكن المسافر الذكي يعرف الجمل الأساسية. ستتعلم كلمات الشرطة، المستشفى، فقدان الأشياء، وطلب المساعدة.`, vocab: [{pl: `policja`, ar: `شرطة`, ipa: `پوليتسيا`},{pl: `szpital`, ar: `مستشفى`, ipa: `شپيتال`},{pl: `pomoc`, ar: `مساعدة`, ipa: `پوموتس`},{pl: `telefon`, ar: `هاتف`, ipa: `تيليفون`},{pl: `zgubiłem`, ar: `أضعتُ، للمتكلم الرجل`, ipa: `زگوبيوِم`},{pl: `zgubiłam`, ar: `أضعتُ، للمتكلمة المرأة`, ipa: `زگوبيوام`},{pl: `portfel`, ar: `محفظة`, ipa: `پورتفيل`},{pl: `paszport`, ar: `جواز سفر`, ipa: `پاشپورت`},{pl: `niebezpieczne`, ar: `خطير`, ipa: `نيه بيزپييتشنه`},{pl: `adres`, ar: `عنوان`, ipa: `أدريس`}], phrases: [{pl: `Proszę o pomoc.`, ar: `أطلب المساعدة.`, ipa: `بروشه أو پوموتس`},{pl: `Potrzebuję policji.`, ar: `أحتاج إلى الشرطة.`, ipa: `پوتشيبوييه پوليتسْيي`},{pl: `Potrzebuję szpitala.`, ar: `أحتاج إلى مستشفى.`, ipa: `پوتشيبوييه شپيتالا`},{pl: `Zgubiłem paszport.`, ar: `أضعت جواز سفري.`, ipa: `زگوبيوِم پاشپورت`},{pl: `Zgubiłam portfel.`, ar: `أضعت محفظتي.`, ipa: `زگوبيوام پورتفيل`},{pl: `To jest niebezpieczne.`, ar: `هذا خطير.`, ipa: `تو ييست نيه بيزپييتشنه`}], grammar: `في الماضي، صيغة المتكلم تختلف حسب الجنس: الرجل يقول zgubiłem، والمرأة تقول zgubiłam. هذه قاعدة مهمة جداً عند الحديث عن شيء حدث لك. احفظ الصيغة التي تناسبك مع paszport وportfel.`, practice: [`قل: أحتاج إلى الشرطة.`,`قل: أحتاج إلى مستشفى.`,`اختر الصيغة المناسبة لك: zgubiłem أو zgubiłam.`,`قل إنك أضعت جواز السفر.`,`اكتب ثلاث جمل طوارئ قصيرة.`]},{day: 19, title: `الحديث عن العائلة والأصدقاء`, title_native: `Rodzina i przyjaciele`, focus: `عند التعارف مع أشخاص في بولندا، قد تسأل عن العائلة أو تذكر من تسافر معه. هذا الدرس يضيف لمسة اجتماعية إلى محادثاتك.`, vocab: [{pl: `rodzina`, ar: `عائلة`, ipa: `روجينا`},{pl: `mama`, ar: `أم`, ipa: `ماما`},{pl: `tata`, ar: `أب`, ipa: `تاتا`},{pl: `brat`, ar: `أخ`, ipa: `برات`},{pl: `siostra`, ar: `أخت`, ipa: `شيوسترا`},{pl: `przyjaciel`, ar: `صديق مقرّب`, ipa: `پشياتشيل`},{pl: `przyjaciółka`, ar: `صديقة مقرّبة`, ipa: `پشياتشووكا`},{pl: `dziecko`, ar: `طفل`, ipa: `جييتسكو`},{pl: `żona`, ar: `زوجة`, ipa: `ژونا`},{pl: `mąż`, ar: `زوج`, ipa: `موش`}], phrases: [{pl: `To moja rodzina.`, ar: `هذه عائلتي.`, ipa: `تو مويا روجينا`},{pl: `Podróżuję z przyjacielem.`, ar: `أسافر مع صديق.`, ipa: `پودروژوييه ز پشياتشييليم`},{pl: `Podróżuję z rodziną.`, ar: `أسافر مع العائلة.`, ipa: `پودروژوييه ز روجينو`},{pl: `Mam brata.`, ar: `لدي أخ.`, ipa: `مام براتا`},{pl: `Mam siostrę.`, ar: `لدي أخت.`, ipa: `مام شيوستره`},{pl: `Czy masz dzieci?`, ar: `هل لديك أطفال؟`, ipa: `تشي ماش جييتشي`}], grammar: `الفعل mam يعني “لدي”، ويستخدم مع الأشخاص والأشياء: Mam brata، Mam telefon. بعد mam تتغير بعض الكلمات، مثل siostra تصبح siostrę. في المحادثة احفظ الصيغ الأكثر شيوعاً بدلاً من التفكير في القاعدة.`, practice: [`قل: هذه عائلتي.`,`قل إنك تسافر مع العائلة.`,`قل إن لديك أخاً أو أختاً.`,`اسأل شخصاً بطريقة غير رسمية إن لديه أطفال.`,`اكتب ثلاث كلمات عن العائلة بالبولندية.`]},{day: 20, title: `الحديث المهذب مع السكان المحليين`, title_native: `Uprzejma rozmowa z mieszkańcami`, focus: `في لقاءات عابرة في مقهى أو قطار، ستحتاج إلى عبارات لطيفة وغير معقدة. ستتعلم كيف تسأل عن الحال وترد بطريقة طبيعية.`, vocab: [{pl: `dobrze`, ar: `جيداً`, ipa: `دوبژه`},{pl: `źle`, ar: `سيئاً`, ipa: `ژلي`},{pl: `świetnie`, ar: `رائع`, ipa: `شفييتنيه`},{pl: `zmęczony`, ar: `متعب، رجل`, ipa: `زميينچوني`},{pl: `zmęczona`, ar: `متعبة، امرأة`, ipa: `زميينچونا`},{pl: `miasto`, ar: `مدينة`, ipa: `مياستو`},{pl: `ładne`, ar: `جميل`, ipa: `وادنه`},{pl: `ludzie`, ar: `الناس`, ipa: `لوجيه`},{pl: `spokojnie`, ar: `بهدوء`, ipa: `سپوكوينه`},{pl: `miły`, ar: `لطيف`, ipa: `ميوي`}], phrases: [{pl: `Jak się masz?`, ar: `كيف حالك؟`, ipa: `ياك شيه ماش`},{pl: `Dobrze, dziękuję.`, ar: `بخير، شكراً.`, ipa: `دوبژه جينكوويه`},{pl: `Bardzo mi miło.`, ar: `سررت كثيراً.`, ipa: `باردزو مي ميوو`},{pl: `To miasto jest ładne.`, ar: `هذه المدينة جميلة.`, ipa: `تو مياستو ييست وادنه`},{pl: `Ludzie są mili.`, ar: `الناس لطفاء.`, ipa: `لوجيه سو ميلي`},{pl: `Jestem zmęczony.`, ar: `أنا متعب.`, ipa: `ييستم زميينچوني`}], grammar: `الصفات قد تتغير حسب الجنس. الرجل يقول Jestem zmęczony، والمرأة تقول Jestem zmęczona. كلمة ładne مناسبة لكلمة miasto لأنها محايدة، لذلك تقول To miasto jest ładne.`, practice: [`اسأل: كيف حالك؟`,`أجب: بخير، شكراً.`,`قل إن المدينة جميلة.`,`اختر الصيغة المناسبة: zmęczony أو zmęczona.`,`اكتب مجاملة بسيطة عن الناس أو المدينة.`]},{day: 21, title: `في السوق وشراء الطعام`, title_native: `Na targu i kupowanie jedzenia`, focus: `الأسواق البولندية مكان رائع لشراء الفواكه والخبز والجبن. ستتعلم كيف تطلب كمية بسيطة وتتعامل مع البائع.`, vocab: [{pl: `targ`, ar: `سوق`, ipa: `تارگ`},{pl: `chleb`, ar: `خبز`, ipa: `خليب`},{pl: `ser`, ar: `جبن`, ipa: `سير`},{pl: `jabłko`, ar: `تفاحة`, ipa: `يابوكو`},{pl: `banan`, ar: `موزة`, ipa: `بانان`},{pl: `pomidor`, ar: `طماطم`, ipa: `پوميدور`},{pl: `ziemniaki`, ar: `بطاطس`, ipa: `ژييمْنياكي`},{pl: `kilo`, ar: `كيلو`, ipa: `كيلو`},{pl: `świeże`, ar: `طازج`, ipa: `شفييژه`},{pl: `sprzedawca`, ar: `بائع`, ipa: `سپشيدافتسا`}], phrases: [{pl: `Poproszę kilo jabłek.`, ar: `أريد كيلو تفاح.`, ipa: `پوپروشه كيلو يابوِك`},{pl: `Czy to jest świeże?`, ar: `هل هذا طازج؟`, ipa: `تشي تو ييست شفييژه`},{pl: `Poproszę chleb.`, ar: `أريد خبزاً.`, ipa: `پوپروشه خليب`},{pl: `Ile za kilo?`, ar: `كم للكيلو؟`, ipa: `إيله زا كيلو`},{pl: `To wszystko, dziękuję.`, ar: `هذا كل شيء، شكراً.`, ipa: `تو فشيستكو جينكوويه`},{pl: `Nie potrzebuję torby.`, ar: `لا أحتاج إلى كيس.`, ipa: `نيه پوتشيبوييه توربي`}], grammar: `في السوق تستخدم Poproszę كثيراً، ثم الكمية والشيء. عبارة To wszystko تعني “هذا كل شيء”، وهي ممتازة لإنهاء الطلب. إذا أردت رفض شيء بأدب، ابدأ بـ Nie potrzebuję...`, practice: [`اطلب كيلو تفاح.`,`اسأل إن كان الشيء طازجاً.`,`قل: هذا كل شيء، شكراً.`,`قل إنك لا تحتاج إلى كيس.`,`اكتب قائمة شراء قصيرة بثلاث كلمات بولندية.`]},{day: 22, title: `الحجز عبر الهاتف أو الاستقبال`, title_native: `Rezerwacja telefoniczna lub w recepcji`, focus: `ستتعلم كيف تحجز طاولة أو موعداً بسيطاً. هذه المهارة مفيدة في المطاعم، الجولات، وصالونات الحلاقة أثناء السفر.`, vocab: [{pl: `rezerwacja`, ar: `حجز`, ipa: `ريزيرڤاتسيا`},{pl: `stolik`, ar: `طاولة`, ipa: `ستوليك`},{pl: `osoba`, ar: `شخص`, ipa: `أوسوبا`},{pl: `godzina`, ar: `ساعة`, ipa: `گودجينا`},{pl: `dzisiaj`, ar: `اليوم`, ipa: `جيشاي`},{pl: `jutro`, ar: `غداً`, ipa: `يوترو`},{pl: `wolne`, ar: `متاح / فارغ`, ipa: `ڤولنه`},{pl: `zajęte`, ar: `مشغول`, ipa: `زايينته`},{pl: `telefon`, ar: `هاتف`, ipa: `تيليفون`},{pl: `nazwisko`, ar: `اسم العائلة`, ipa: `نازفيسكو`}], phrases: [{pl: `Chcę zrobić rezerwację.`, ar: `أريد أن أحجز.`, ipa: `ختسه زروبيتش ريزيرڤاتسيه`},{pl: `Stolik dla dwóch osób.`, ar: `طاولة لشخصين.`, ipa: `ستوليك دلا دڤوخ أوسوب`},{pl: `Na dziś wieczór.`, ar: `لهذا المساء.`, ipa: `نا جيش ڤييتشور`},{pl: `Na jutro o ósmej.`, ar: `لغدٍ في الساعة الثامنة.`, ipa: `نا يوترو أو أوسميي`},{pl: `Czy są wolne miejsca?`, ar: `هل توجد أماكن متاحة؟`, ipa: `تشي سو ڤولنه مييسْتسا`},{pl: `Na nazwisko Ahmed.`, ar: `باسم أحمد.`, ipa: `نا نازفيسكو أحمد`}], grammar: `كلمة dla تعني “لـ” وتستخدم عند الحجز: dla dwóch osób، dla czterech osób. عبارة o ósmej تعني “في الساعة الثامنة”. عند ذكر اسم الحجز، استخدم Na nazwisko...`, practice: [`قل: أريد أن أحجز.`,`اطلب طاولة لشخصين.`,`احجز لغد في الثامنة.`,`اسأل إن توجد أماكن متاحة.`,`اكتب جملة حجز باسمك.`]},{day: 23, title: `وصف المكان والسكن`, title_native: `Opisywanie miejsca i noclegu`, focus: `ستحتاج أحياناً إلى وصف الفندق أو الشقة أو الحي الذي تسكن فيه. هذا الدرس يساعدك على التعبير عن الراحة، النظافة، والقرب من المركز.`, vocab: [{pl: `mieszkanie`, ar: `شقة`, ipa: `مييشكانيه`},{pl: `pokój`, ar: `غرفة`, ipa: `پوكوي`},{pl: `łazienka`, ar: `حمام`, ipa: `وازيينكا`},{pl: `kuchnia`, ar: `مطبخ`, ipa: `كوخنيا`},{pl: `czysto`, ar: `نظيف`, ipa: `تشيستو`},{pl: `brudno`, ar: `متسخ`, ipa: `برودنو`},{pl: `cicho`, ar: `هادئ`, ipa: `چيخو`},{pl: `głośno`, ar: `صاخب`, ipa: `گلوشنو`},{pl: `wygodnie`, ar: `مريح`, ipa: `ڤيگودنيه`},{pl: `centrum`, ar: `المركز`, ipa: `تسنتروم`}], phrases: [{pl: `Pokój jest czysty.`, ar: `الغرفة نظيفة.`, ipa: `پوكوي ييست تشيستي`},{pl: `Jest tu cicho.`, ar: `هنا هادئ.`, ipa: `ييست تو چيخو`},{pl: `Jest za głośno.`, ar: `المكان صاخب جداً.`, ipa: `ييست زا گلوشنو`},{pl: `Łazienka jest mała.`, ar: `الحمام صغير.`, ipa: `وازيينكا ييست ماوا`},{pl: `Mieszkanie jest blisko centrum.`, ar: `الشقة قريبة من المركز.`, ipa: `مييشكانيه ييست بليسكو تسنتروم`},{pl: `To jest wygodne.`, ar: `هذا مريح.`, ipa: `تو ييست ڤيگودنه`}], grammar: `لوصف الحالة العامة للمكان، استخدم Jest tu... مثل Jest tu cicho، أي “هنا هادئ”. أما لوصف شيء محدد، استخدم الاسم + jest + الصفة: Pokój jest czysty. Łazienka jest mała.`, practice: [`قل إن الغرفة نظيفة.`,`قل إن الشقة قريبة من المركز.`,`اشتكِ بأن المكان صاخب جداً.`,`صف الحمام بكلمة mała أو czysta.`,`اكتب وصفاً من ثلاث جمل لفندقك الخيالي.`]},{day: 24, title: `المشاعر والتفضيلات`, title_native: `Uczucia i preferencje`, focus: `عندما تسافر، ستحتاج إلى قول ما تحب وما لا تحب وما تشعر به. هذا الدرس يجعل كلامك أكثر طبيعية في المحادثات اليومية.`, vocab: [{pl: `lubię`, ar: `أحب`, ipa: `لوبييه`},{pl: `nie lubię`, ar: `لا أحب`, ipa: `نيه لوبييه`},{pl: `chcę`, ar: `أريد`, ipa: `ختسه`},{pl: `wolę`, ar: `أفضّل`, ipa: `ڤوله`},{pl: `szczęśliwy`, ar: `سعيد، رجل`, ipa: `شتشنشليڤي`},{pl: `szczęśliwa`, ar: `سعيدة، امرأة`, ipa: `شتشنشليڤا`},{pl: `głodny`, ar: `جائع، رجل`, ipa: `گوودني`},{pl: `głodna`, ar: `جائعة، امرأة`, ipa: `گوودنا`},{pl: `spragniony`, ar: `عطشان، رجل`, ipa: `سپراگنيوني`},{pl: `zmęczony`, ar: `متعب، رجل`, ipa: `زميينچوني`}], phrases: [{pl: `Lubię polskie jedzenie.`, ar: `أحب الطعام البولندي.`, ipa: `لوبييه پولسكيه ييدزينيه`},{pl: `Nie lubię zimna.`, ar: `لا أحب البرد.`, ipa: `نيه لوبييه ژيمنا`},{pl: `Chcę odpocząć.`, ar: `أريد أن أرتاح.`, ipa: `ختسه أودپوتشونتش`},{pl: `Wolę kawę.`, ar: `أفضّل القهوة.`, ipa: `ڤوله كاڤه`},{pl: `Jestem głodny.`, ar: `أنا جائع.`, ipa: `ييستم گوودني`},{pl: `Jestem szczęśliwa.`, ar: `أنا سعيدة.`, ipa: `ييستم شتشنشليڤا`}], grammar: `الأفعال lubię وwolę تأتي غالباً مع شيء تحبه أو تفضله. الصفات الشخصية مثل głodny وszczęśliwy تتغير حسب المتكلم: الرجل يقول głodny، والمرأة تقول głodna. احفظ زوج الصيغ الذي تحتاجه عند السفر.`, practice: [`قل إنك تحب الطعام البولندي.`,`قل إنك تفضّل القهوة.`,`قل إنك جائع أو جائعة.`,`قل إنك لا تحب البرد.`,`اكتب ثلاث جمل عن تفضيلاتك في السفر.`]},{day: 25, title: `الدعوات والاقتراحات`, title_native: `Zaproszenia i propozycje`, focus: `إذا تعرفت على سكان محليين أو مسافرين آخرين، ستحتاج إلى اقتراح قهوة أو نزهة. هذا الدرس يساعدك على المبادرة والرد بأدب.`, vocab: [{pl: `kawa`, ar: `قهوة`, ipa: `كاڤا`},{pl: `spacer`, ar: `نزهة / مشي`, ipa: `سپاتسير`},{pl: `kino`, ar: `سينما`, ipa: `كينو`},{pl: `dziś`, ar: `اليوم`, ipa: `جيش`},{pl: `jutro`, ar: `غداً`, ipa: `يوترو`},{pl: `razem`, ar: `معاً`, ipa: `رازيم`},{pl: `może`, ar: `ربما / هل يمكن`, ipa: `موژه`},{pl: `chętnie`, ar: `بكل سرور`, ipa: `خينتنيه`},{pl: `niestety`, ar: `للأسف`, ipa: `نيستِتي`},{pl: `czas`, ar: `وقت`, ipa: `تشاس`}], phrases: [{pl: `Może kawa?`, ar: `ما رأيك بقهوة؟`, ipa: `موژه كاڤا`},{pl: `Chcesz iść na spacer?`, ar: `هل تريد أن تذهب للمشي؟`, ipa: `ختشِش إيشتش نا سپاتسير`},{pl: `Chętnie.`, ar: `بكل سرور.`, ipa: `خينتنيه`},{pl: `Niestety nie mam czasu.`, ar: `للأسف ليس لدي وقت.`, ipa: `نيستِتي نيه مام تشاسو`},{pl: `Może jutro?`, ar: `ربما غداً؟`, ipa: `موژه يوترو`},{pl: `Idziemy razem?`, ar: `هل نذهب معاً؟`, ipa: `إيدجيمي رازيم`}], grammar: `كلمة może مفيدة جداً لأنها تجعل الاقتراح لطيفاً وغير مباشر. الفعل chcesz يعني “هل تريد؟” ويستخدم مع شخص تتحدث معه بشكل غير رسمي. في المواقف الرسمية يمكنك استخدام Czy chce pan...? أو Czy chce pani...?`, practice: [`اقترح قهوة بجملة قصيرة.`,`ادعُ شخصاً للمشي.`,`اقبل الدعوة بقول Chętnie.`,`ارفض بأدب لأنك لا تملك وقتاً.`,`اقترح موعداً بقول Może jutro?`]},{day: 26, title: `حل المشكلات اليومية`, title_native: `Rozwiązywanie codziennych problemów`, focus: `قد لا يعمل المفتاح، أو يتأخر القطار، أو يكون الطلب خاطئاً. ستتعلم كيف تشرح مشكلة بسيطة بدون توتر.`, vocab: [{pl: `problem`, ar: `مشكلة`, ipa: `پروبليم`},{pl: `nie działa`, ar: `لا يعمل`, ipa: `نيه دجاوا`},{pl: `klucz`, ar: `مفتاح`, ipa: `كلوتش`},{pl: `internet`, ar: `إنترنت`, ipa: `إينترنت`},{pl: `bilet`, ar: `تذكرة`, ipa: `بيليت`},{pl: `zamówienie`, ar: `طلب`, ipa: `زاموڤيينيه`},{pl: `pomyłka`, ar: `خطأ / التباس`, ipa: `پوميوكا`},{pl: `opóźnienie`, ar: `تأخير`, ipa: `أوپوجنيينيه`},{pl: `pomóc`, ar: `يساعد`, ipa: `پوموتس`},{pl: `naprawić`, ar: `يصلح`, ipa: `ناپراڤيتش`}], phrases: [{pl: `Mam problem.`, ar: `لدي مشكلة.`, ipa: `مام پروبليم`},{pl: `Klucz nie działa.`, ar: `المفتاح لا يعمل.`, ipa: `كلوتش نيه دجاوا`},{pl: `Internet nie działa.`, ar: `الإنترنت لا يعمل.`, ipa: `إينترنت نيه دجاوا`},{pl: `To nie moje zamówienie.`, ar: `هذا ليس طلبي.`, ipa: `تو نيه مويه زاموڤيينيه`},{pl: `To chyba pomyłka.`, ar: `أظن أن هذا خطأ.`, ipa: `تو خيبا پوميوكا`},{pl: `Czy może mi pan pomóc?`, ar: `هل يمكنك مساعدتي؟`, ipa: `تشي موژه مي بان پوموتس`}], grammar: `عبارة nie działa تستخدم لأي شيء لا يعمل: internet، klucz، telefon. كلمة chyba تعني “أظن / ربما”، وتجعل الجملة ألطف: To chyba pomyłka أقل حدة من “هذا خطأ”.`, practice: [`قل: لدي مشكلة.`,`قل إن الإنترنت لا يعمل.`,`قل إن هذا ليس طلبك.`,`اطلب المساعدة من رجل بأدب.`,`اكتب ثلاث مشكلات سفر قصيرة بالبولندية.`]},{day: 27, title: `المحادثة في مكان العمل أو مساحة مشتركة`, title_native: `Rozmowa w pracy lub wspólnej przestrzeni`, focus: `كثير من المسافرين يعملون عن بعد من المقاهي أو مساحات العمل في وارسو. ستتعلم عبارات عن الواي فاي، المقبس، الهدوء، والعمل.`, vocab: [{pl: `praca`, ar: `عمل`, ipa: `پراتسا`},{pl: `komputer`, ar: `كمبيوتر`, ipa: `كومپوتر`},{pl: `internet`, ar: `إنترنت`, ipa: `إينترنت`},{pl: `hasło`, ar: `كلمة مرور`, ipa: `هاسوو`},{pl: `gniazdko`, ar: `مقبس كهربائي`, ipa: `گنياستكو`},{pl: `stół`, ar: `طاولة`, ipa: `ستوو`},{pl: `krzesło`, ar: `كرسي`, ipa: `كشيسوو`},{pl: `cicho`, ar: `هادئ`, ipa: `چيخو`},{pl: `spotkanie`, ar: `اجتماع`, ipa: `سپوتكانيه`},{pl: `email`, ar: `بريد إلكتروني`, ipa: `إيميل`}], phrases: [{pl: `Jakie jest hasło do Wi-Fi?`, ar: `ما كلمة مرور الواي فاي؟`, ipa: `ياكيه ييست هاسوو دو واي فاي`},{pl: `Czy jest gniazdko?`, ar: `هل يوجد مقبس؟`, ipa: `تشي ييست گنياستكو`},{pl: `Muszę pracować.`, ar: `يجب أن أعمل.`, ipa: `موشه پراتسوڤاتش`},{pl: `Mam spotkanie online.`, ar: `لدي اجتماع عبر الإنترنت.`, ipa: `مام سپوتكانيه أونلاين`},{pl: `Czy tu jest cicho?`, ar: `هل المكان هادئ هنا؟`, ipa: `تشي تو ييست چيخو`},{pl: `Potrzebuję stołu.`, ar: `أحتاج إلى طاولة.`, ipa: `پوتشيبوييه ستووو`}], grammar: `كلمة muszę تعني “يجب أن / أحتاج أن”، وبعدها يأتي الفعل بصيغته الأساسية: Muszę pracować. Muszę odpocząć. هذه صيغة مفيدة عندما تشرح حاجتك بسرعة.`, practice: [`اسأل عن كلمة مرور الواي فاي.`,`اسأل عن المقبس.`,`قل إن لديك اجتماعاً عبر الإنترنت.`,`قل إنك يجب أن تعمل.`,`اكتب جملتين عن مقهى مناسب للعمل.`]},{day: 28, title: `المقارنة والاختيار`, title_native: `Porównywanie i wybieranie`, focus: `ستحتاج إلى الاختيار بين تذكرتين، طبقين، أو طريقين. هذا الدرس يساعدك على قول الأفضل، الأرخص، الأقرب، والأسرع.`, vocab: [{pl: `lepszy`, ar: `أفضل، مذكر`, ipa: `ليپشي`},{pl: `lepsza`, ar: `أفضل، مؤنث`, ipa: `ليپشا`},{pl: `tańszy`, ar: `أرخص، مذكر`, ipa: `تانشي`},{pl: `droższy`, ar: `أغلى، مذكر`, ipa: `دروژشي`},{pl: `bliżej`, ar: `أقرب`, ipa: `بليژيي`},{pl: `dalej`, ar: `أبعد`, ipa: `داليي`},{pl: `szybciej`, ar: `أسرع`, ipa: `شيپچيېي`},{pl: `wolniej`, ar: `أبطأ`, ipa: `ڤولنيي`},{pl: `wybór`, ar: `اختيار`, ipa: `ڤيبور`},{pl: `opcja`, ar: `خيار`, ipa: `أوپتسيا`}], phrases: [{pl: `Która opcja jest lepsza?`, ar: `أي خيار أفضل؟`, ipa: `كتورا أوپتسيا ييست ليپشا`},{pl: `Ten bilet jest tańszy.`, ar: `هذه التذكرة أرخص.`, ipa: `تين بيليت ييست تانشي`},{pl: `Ten hotel jest droższy.`, ar: `هذا الفندق أغلى.`, ipa: `تين هوتيل ييست دروژشي`},{pl: `Czy to jest bliżej?`, ar: `هل هذا أقرب؟`, ipa: `تشي تو ييست بليژيي`},{pl: `Chcę szybszą opcję.`, ar: `أريد الخيار الأسرع.`, ipa: `ختسه شيپشو أوپتسيه`},{pl: `Wybieram to.`, ar: `أختار هذا.`, ipa: `ڤيبييرام تو`}], grammar: `في البولندية تتغير الصفات حسب الاسم، لذلك ترى lepszy وlepsza. في السفر لا تحتاج إلى إتقان كل النهايات فوراً؛ ركز على الأسئلة العامة مثل Która opcja jest lepsza? وCzy to jest bliżej?`, practice: [`اسأل أي خيار أفضل.`,`قل إن التذكرة أرخص.`,`قل إن الفندق أغلى.`,`اسأل إن كان المكان أقرب.`,`قل: أختار هذا.`]},{day: 29, title: `مراجعة السفر الكامل`, title_native: `Powtórka podróżna`, focus: `اليوم يجمع أهم العبارات من الوصول إلى الطعام والنقل والفندق. تخيل أنك تقضي يوماً كاملاً في وارسو وتستخدم البولندية في كل خطوة.`, vocab: [{pl: `dzień`, ar: `يوم`, ipa: `جين`},{pl: `plan`, ar: `خطة`, ipa: `پلان`},{pl: `miasto`, ar: `مدينة`, ipa: `مياستو`},{pl: `bilet`, ar: `تذكرة`, ipa: `بيليت`},{pl: `jedzenie`, ar: `طعام`, ipa: `ييدزينيه`},{pl: `hotel`, ar: `فندق`, ipa: `هوتيل`},{pl: `pomoc`, ar: `مساعدة`, ipa: `پوموتس`},{pl: `adres`, ar: `عنوان`, ipa: `أدريس`},{pl: `pieniądze`, ar: `مال`, ipa: `پيينوندزه`},{pl: `telefon`, ar: `هاتف`, ipa: `تيليفون`}], phrases: [{pl: `Dzień dobry, mam rezerwację.`, ar: `صباح الخير، لدي حجز.`, ipa: `جين دوبري مام ريزيرڤاتسيه`},{pl: `Poproszę bilet do centrum.`, ar: `أريد تذكرة إلى المركز.`, ipa: `پوپروشه بيليت دو تسنتروم`},{pl: `Gdzie jest restauracja?`, ar: `أين المطعم؟`, ipa: `گجيه ييست ريستورانتسيا`},{pl: `Rachunek, proszę.`, ar: `الفاتورة، من فضلك.`, ipa: `راخونِك بروشه`},{pl: `Potrzebuję pomocy.`, ar: `أحتاج إلى مساعدة.`, ipa: `پوتشيبوييه پوموتسي`},{pl: `Do widzenia i dziękuję.`, ar: `إلى اللقاء وشكراً.`, ipa: `دو فيدزينيا إي جينكوويه`}], grammar: `في هذا المستوى، أهم مهارة هي تركيب الجمل الجاهزة مع كلمات جديدة. إذا عرفت Gdzie jest...? يمكنك السؤال عن hotel، restauracja، apteka، przystanek. وإذا عرفت Poproszę... يمكنك طلب قهوة، تذكرة، كيس، أو فاتورة.`, practice: [`اكتب ثلاث جمل تبدأ بـ Gdzie jest...?`,`اكتب ثلاث طلبات تبدأ بـ Poproszę...`,`تخيل أنك تدخل فندقاً واكتب جملتين.`,`تخيل أنك في مطعم واكتب جملتين.`,`راجع عشرة كلمات من الأيام السابقة بصوت عالٍ.`]},{day: 30, title: `محادثة طبيعية قصيرة في بولندا`, title_native: `Krótka naturalna rozmowa w Polsce`, focus: `في اليوم الأخير ستجمع التحيات، الأسئلة، الطلبات، والمجاملات في محادثة طبيعية. الهدف هو أن تبدو واثقاً ومهذباً حتى لو كانت جملك بسيطة.`, vocab: [{pl: `rozmowa`, ar: `محادثة`, ipa: `روزموڤا`},{pl: `pytanie`, ar: `سؤال`, ipa: `پيتانيه`},{pl: `odpowiedź`, ar: `جواب`, ipa: `أودپوڤييتش`},{pl: `prośba`, ar: `طلب`, ipa: `پروشبا`},{pl: `uprzejmie`, ar: `بأدب`, ipa: `أوپشييميه`},{pl: `naturalnie`, ar: `بشكل طبيعي`, ipa: `ناتورالنيه`},{pl: `łatwe`, ar: `سهل`, ipa: `واتفه`},{pl: `trudne`, ar: `صعب`, ipa: `ترودنه`},{pl: `powoli`, ar: `ببطء`, ipa: `پوڤولي`},{pl: `razem`, ar: `معاً`, ipa: `رازيم`}], phrases: [{pl: `Mam pytanie.`, ar: `لدي سؤال.`, ipa: `مام پيتانيه`},{pl: `Czy może pan powtórzyć?`, ar: `هل يمكنك التكرار؟`, ipa: `تشي موژه بان پوفتوژيتش`},{pl: `Czy może pani powtórzyć?`, ar: `هل يمكنكِ التكرار؟`, ipa: `تشي موژه باني پوفتوژيتش`},{pl: `Uczę się polskiego.`, ar: `أتعلم البولندية.`, ipa: `أوتشه شيه پولسكييگو`},{pl: `Polski jest trudny, ale piękny.`, ar: `البولندية صعبة لكنها جميلة.`, ipa: `پولسكي ييست ترودني أليه پيينكني`},{pl: `Dziękuję za pomoc.`, ar: `شكراً على المساعدة.`, ipa: `جينكوويه زا پوموتس`}], grammar: `عبارة uczę się تعني “أتعلم”، وبعدها polskiego أي “البولندية”. عندما تخبر الناس أنك تتعلم لغتهم، غالباً سيصبحون أكثر صبراً وتعاوناً. استخدم powoli أو Proszę mówić wolno عندما تحتاج إلى وقت للفهم.`, practice: [`قل: أتعلم البولندية.`,`اطلب من شخص أن يكرر الجملة.`,`قل إن البولندية صعبة لكنها جميلة.`,`اشكر شخصاً على المساعدة.`,`اكتب محادثة من ستة أسطر تجمع التحية، السؤال، الطلب، والشكر.`]}];

var CONVERSATIONS_AR_PL = [{id: 1, title: `طلب قهوة في مقهى في كراكوف`, scene: `تدخل مقهى صغيراً قرب الساحة الرئيسية في كراكوف. المكان مزدحم قليلاً، وتريد طلب قهوة وقطعة كعك بطريقة مهذبة.`, lines: [{who: `them`, pl: `Dzień dobry, co podać?`, ar: `صباح الخير، ماذا أقدم لك؟`},{who: `you`, pl: `Dzień dobry, poproszę kawę z mlekiem.`, ar: `صباح الخير، أريد قهوة مع الحليب من فضلك.`},{who: `them`, pl: `Mała czy duża?`, ar: `صغيرة أم كبيرة؟`},{who: `you`, pl: `Duża, proszę.`, ar: `كبيرة، من فضلك.`},{who: `them`, pl: `Czy coś jeszcze?`, ar: `هل تريد شيئاً آخر؟`},{who: `you`, pl: `Tak, poproszę ciasto.`, ar: `نعم، أريد قطعة كعك من فضلك.`},{who: `them`, pl: `Z cukrem?`, ar: `مع السكر؟`},{who: `you`, pl: `Nie, bez cukru, proszę.`, ar: `لا، بدون سكر من فضلك.`},{who: `them`, pl: `To będzie osiemnaście złotych.`, ar: `سيكون المجموع ثمانية عشر زلوتي.`},{who: `you`, pl: `Czy mogę płacić kartą?`, ar: `هل يمكنني الدفع بالبطاقة؟`},{who: `them`, pl: `Tak, oczywiście.`, ar: `نعم، بالتأكيد.`},{who: `you`, pl: `Dziękuję bardzo.`, ar: `شكراً جزيلاً.`}]},{id: 2, title: `تسجيل الدخول في فندق في وارسو`, scene: `تصل إلى فندق في وسط وارسو بعد رحلة طويلة. تريد إخبار موظف الاستقبال أن لديك حجزاً وتسأل عن المصعد والفطور.`, lines: [{who: `them`, pl: `Dobry wieczór, witamy w hotelu.`, ar: `مساء الخير، أهلاً بك في الفندق.`},{who: `you`, pl: `Dobry wieczór, mam rezerwację.`, ar: `مساء الخير، لدي حجز.`},{who: `them`, pl: `Na jakie nazwisko?`, ar: `باسم أي عائلة؟`},{who: `you`, pl: `Na nazwisko Ahmed.`, ar: `باسم أحمد.`},{who: `them`, pl: `Poproszę paszport.`, ar: `جواز السفر من فضلك.`},{who: `you`, pl: `Proszę, to mój paszport.`, ar: `تفضل، هذا جواز سفري.`},{who: `them`, pl: `Dziękuję, pokój numer trzydzieści dwa.`, ar: `شكراً، الغرفة رقم اثنين وثلاثين.`},{who: `you`, pl: `Gdzie jest winda?`, ar: `أين المصعد؟`},{who: `them`, pl: `Winda jest po prawej stronie.`, ar: `المصعد على الجهة اليمنى.`},{who: `you`, pl: `Czy jest śniadanie?`, ar: `هل يوجد فطور؟`},{who: `them`, pl: `Tak, od siódmej do dziesiątej.`, ar: `نعم، من السابعة إلى العاشرة.`},{who: `you`, pl: `Dziękuję, dobranoc.`, ar: `شكراً، تصبح على خير.`}]},{id: 3, title: `السؤال عن الاتجاهات في غدانسك`, scene: `أنت في مدينة غدانسك وتبحث عن شارع دووغا الشهير. توقف شخصاً محلياً وتسأله بأدب عن الطريق.`, lines: [{who: `you`, pl: `Przepraszam, mam pytanie.`, ar: `عفواً، لدي سؤال.`},{who: `them`, pl: `Tak, słucham.`, ar: `نعم، تفضل.`},{who: `you`, pl: `Gdzie jest ulica Długa?`, ar: `أين شارع دووغا؟`},{who: `them`, pl: `Proszę iść prosto.`, ar: `امشِ إلى الأمام من فضلك.`},{who: `you`, pl: `Prosto?`, ar: `إلى الأمام؟`},{who: `them`, pl: `Tak, potem w lewo.`, ar: `نعم، ثم إلى اليسار.`},{who: `you`, pl: `Czy to daleko?`, ar: `هل هو بعيد؟`},{who: `them`, pl: `Nie, to bardzo blisko.`, ar: `لا، إنه قريب جداً.`},{who: `you`, pl: `Ile minut?`, ar: `كم دقيقة؟`},{who: `them`, pl: `Może pięć minut.`, ar: `ربما خمس دقائق.`},{who: `you`, pl: `Dziękuję za pomoc.`, ar: `شكراً على المساعدة.`},{who: `them`, pl: `Nie ma za co.`, ar: `لا شكر على واجب.`}]},{id: 4, title: `في مطعم بولندي تقليدي`, scene: `تجلس في مطعم في بوزنان وتريد تجربة طعام بولندي. تسأل النادلة عن القائمة وتطلب pierogi بدون لحم.`, lines: [{who: `them`, pl: `Dzień dobry, czy mogę pomóc?`, ar: `صباح الخير، هل يمكنني المساعدة؟`},{who: `you`, pl: `Dzień dobry, czy mogę prosić menu?`, ar: `صباح الخير، هل يمكنني طلب القائمة؟`},{who: `them`, pl: `Oczywiście, proszę.`, ar: `بالتأكيد، تفضل.`},{who: `you`, pl: `Co pani poleca?`, ar: `ماذا تنصحين؟`},{who: `them`, pl: `Polecam pierogi i zupę.`, ar: `أنصح بالبيروغي والحساء.`},{who: `you`, pl: `Czy pierogi są z mięsem?`, ar: `هل البيروغي باللحم؟`},{who: `them`, pl: `Mamy pierogi z serem albo z mięsem.`, ar: `لدينا بيروغي بالجبن أو باللحم.`},{who: `you`, pl: `Poproszę pierogi z serem.`, ar: `أريد بيروغي بالجبن من فضلك.`},{who: `them`, pl: `Coś do picia?`, ar: `شيء للشرب؟`},{who: `you`, pl: `Wodę, proszę.`, ar: `ماء، من فضلك.`},{who: `them`, pl: `Dobrze, zaraz przyniosę.`, ar: `حسناً، سأحضره حالاً.`},{who: `you`, pl: `Dziękuję bardzo.`, ar: `شكراً جزيلاً.`}]},{id: 5, title: `شراء تذكرة ترام في وارسو`, scene: `أنت في محطة ترام وتريد الوصول إلى مركز المدينة. تسأل موظفاً أو شخصاً محلياً عن التذكرة المناسبة وتفعيلها.`, lines: [{who: `you`, pl: `Przepraszam, jaki bilet do centrum?`, ar: `عفواً، أي تذكرة إلى المركز؟`},{who: `them`, pl: `Bilet dwudziestominutowy wystarczy.`, ar: `تذكرة عشرين دقيقة تكفي.`},{who: `you`, pl: `Gdzie mogę kupić bilet?`, ar: `أين يمكنني شراء تذكرة؟`},{who: `them`, pl: `W automacie obok przystanku.`, ar: `من الجهاز بجانب المحطة.`},{who: `you`, pl: `Czy mogę płacić kartą?`, ar: `هل يمكنني الدفع بالبطاقة؟`},{who: `them`, pl: `Tak, można płacić kartą.`, ar: `نعم، يمكن الدفع بالبطاقة.`},{who: `you`, pl: `Czy muszę skasować bilet?`, ar: `هل يجب أن أفعّل التذكرة؟`},{who: `them`, pl: `Tak, w tramwaju.`, ar: `نعم، داخل الترام.`},{who: `you`, pl: `Czy ten tramwaj jedzie do centrum?`, ar: `هل هذا الترام يذهب إلى المركز؟`},{who: `them`, pl: `Tak, proszę wsiadać.`, ar: `نعم، تفضل بالصعود.`},{who: `you`, pl: `Dziękuję za pomoc.`, ar: `شكراً على المساعدة.`},{who: `them`, pl: `Proszę bardzo.`, ar: `على الرحب والسعة.`}]},{id: 6, title: `شراء تذكار في متجر`, scene: `تدخل متجر هدايا في زاكوباني وتبحث عن تذكار صغير. تريد معرفة السعر والدفع بالبطاقة.`, lines: [{who: `them`, pl: `Dzień dobry, w czym mogę pomóc?`, ar: `صباح الخير، كيف يمكنني المساعدة؟`},{who: `you`, pl: `Dzień dobry, szukam pamiątki.`, ar: `صباح الخير، أبحث عن تذكار.`},{who: `them`, pl: `Mamy magnesy i pocztówki.`, ar: `لدينا مغناطيسات وبطاقات بريدية.`},{who: `you`, pl: `Ile kosztuje ten magnes?`, ar: `كم يكلف هذا المغناطيس؟`},{who: `them`, pl: `Dziesięć złotych.`, ar: `عشرة زلوتي.`},{who: `you`, pl: `Dobrze, poproszę jeden.`, ar: `حسناً، أريد واحداً من فضلك.`},{who: `them`, pl: `Czy potrzebuje pan torby?`, ar: `هل تحتاج إلى كيس؟`},{who: `you`, pl: `Nie, dziękuję.`, ar: `لا، شكراً.`},{who: `them`, pl: `Razem dziesięć złotych.`, ar: `المجموع عشرة زلوتي.`},{who: `you`, pl: `Czy mogę zapłacić kartą?`, ar: `هل يمكنني الدفع بالبطاقة؟`},{who: `them`, pl: `Tak, proszę.`, ar: `نعم، تفضل.`},{who: `you`, pl: `Dziękuję, do widzenia.`, ar: `شكراً، إلى اللقاء.`}]},{id: 7, title: `في الصيدلية`, scene: `تشعر بصداع خفيف أثناء السفر في فروتسواف. تدخل صيدلية وتشرح المشكلة وتسأل إن كانت الوصفة الطبية مطلوبة.`, lines: [{who: `them`, pl: `Dzień dobry, słucham.`, ar: `صباح الخير، تفضل.`},{who: `you`, pl: `Dzień dobry, boli mnie głowa.`, ar: `صباح الخير، رأسي يؤلمني.`},{who: `them`, pl: `Czy ma pan gorączkę?`, ar: `هل لديك حمى؟`},{who: `you`, pl: `Nie, nie mam gorączki.`, ar: `لا، ليس لدي حمى.`},{who: `them`, pl: `Czy ma pan alergię?`, ar: `هل لديك حساسية؟`},{who: `you`, pl: `Nie wiem.`, ar: `لا أعرف.`},{who: `them`, pl: `Mogę polecić ten lek.`, ar: `يمكنني أن أنصح بهذا الدواء.`},{who: `you`, pl: `Czy potrzebna jest recepta?`, ar: `هل الوصفة الطبية ضرورية؟`},{who: `them`, pl: `Nie, recepta nie jest potrzebna.`, ar: `لا، الوصفة ليست ضرورية.`},{who: `you`, pl: `Dobrze, poproszę.`, ar: `حسناً، أريده من فضلك.`},{who: `them`, pl: `Proszę pić dużo wody.`, ar: `من فضلك اشرب الكثير من الماء.`},{who: `you`, pl: `Dziękuję bardzo.`, ar: `شكراً جزيلاً.`}]},{id: 8, title: `حديث قصير مع شخص محلي في القطار`, scene: `تجلس في قطار من وارسو إلى كراكوف بجانب شخص بولندي ودود. تبدأ محادثة بسيطة عن السفر واللغة البولندية.`, lines: [{who: `you`, pl: `Przepraszam, czy to miejsce jest wolne?`, ar: `عفواً، هل هذا المقعد فارغ؟`},{who: `them`, pl: `Tak, proszę.`, ar: `نعم، تفضل.`},{who: `you`, pl: `Dziękuję. Jadę do Krakowa.`, ar: `شكراً. أنا ذاهب إلى كراكوف.`},{who: `them`, pl: `Kraków jest bardzo ładny.`, ar: `كراكوف جميلة جداً.`},{who: `you`, pl: `To moja pierwsza podróż do Polski.`, ar: `هذه أول رحلة لي إلى بولندا.`},{who: `them`, pl: `Naprawdę? Jak się podoba?`, ar: `حقاً؟ كيف أعجبتك؟`},{who: `you`, pl: `Bardzo mi się podoba. Ludzie są mili.`, ar: `أعجبتني جداً. الناس لطفاء.`},{who: `them`, pl: `Czy mówi pan po polsku?`, ar: `هل تتكلم البولندية؟`},{who: `you`, pl: `Uczę się polskiego.`, ar: `أتعلم البولندية.`},{who: `them`, pl: `Bardzo dobrze!`, ar: `جيد جداً!`},{who: `you`, pl: `Polski jest trudny, ale piękny.`, ar: `البولندية صعبة لكنها جميلة.`},{who: `them`, pl: `To prawda. Miłej podróży!`, ar: `هذا صحيح. رحلة سعيدة!`}]}];